from dataclasses import dataclass


@dataclass(frozen=True)
class EndpointConfig:
    service: str
    endpoint: str
    token: str
    revision: int


def load_endpoint(base, overrides):
    return EndpointConfig(
        service=base["service"],
        endpoint=overrides.get("DELIVERY_ENDPOINT", base["endpoint"]),
        token=overrides.get("DELIVERY_TOKEN", base["token"]),
        revision=int(overrides.get("DELIVERY_REVISION", base.get("revision", 0))),
    )

