from dataclasses import dataclass


@dataclass(frozen=True)
class DeliveryReceipt:
    topic: str
    endpoint: str
    credential: str
    payload: object


class DeliveryClient:
    def __init__(self, config):
        self._endpoint = config.endpoint
        self._token = config.token

    def deliver(self, topic, payload):
        return DeliveryReceipt(topic, self._endpoint, self._token, payload)


class ClientPool:
    def __init__(self):
        self._clients = {}

    def acquire(self, config):
        client = self._clients.get(config.service)
        if client is None:
            client = DeliveryClient(config)
            self._clients[config.service] = client
        return client

