class DeliveryRouter:
    def __init__(self, config, pool):
        self._config = config
        self._pool = pool
        self._topic_clients = {}

    def reload(self, config):
        if config.service != self._config.service:
            raise ValueError("service cannot change")
        self._config = config

    def deliver(self, topic, payload):
        client = self._topic_clients.get(topic)
        if client is None:
            client = self._pool.acquire(self._config)
            self._topic_clients[topic] = client
        return client.deliver(topic, payload)

