from delivery.client_pool import ClientPool
from delivery.config import load_endpoint
from delivery.router import DeliveryRouter


def test_base_configuration_delivers_multiple_topics_consistently():
    config = load_endpoint(
        {
            "service": "mailer",
            "endpoint": "https://east.invalid",
            "token": "east-token",
            "revision": 1,
        },
        {},
    )
    router = DeliveryRouter(config, ClientPool())
    first = router.deliver("receipts", {"id": 1})
    second = router.deliver("alerts", {"id": 2})
    assert (first.endpoint, first.credential) == (
        "https://east.invalid",
        "east-token",
    )
    assert (second.endpoint, second.credential) == (
        "https://east.invalid",
        "east-token",
    )


def test_nonempty_canary_override_is_used_on_initial_load():
    config = load_endpoint(
        {
            "service": "mailer",
            "endpoint": "https://stable.invalid",
            "token": "stable-token",
            "revision": 3,
        },
        {
            "DELIVERY_ENDPOINT": "https://canary.invalid",
            "DELIVERY_TOKEN": "canary-token",
            "DELIVERY_REVISION": "4",
        },
    )
    receipt = DeliveryRouter(config, ClientPool()).deliver("probe", "ok")
    assert (receipt.endpoint, receipt.credential) == (
        "https://canary.invalid",
        "canary-token",
    )
